def lru_page_replacement(pages, frames):
    page_faults = 0
    memory = {}
    counter = 0

    for page in pages:
        counter += 1
        if page in memory:
            memory[page] = counter  # Update recent use
        else:
            page_faults += 1
            if len(memory) >= frames:
                # Evict LRU page (lowest counter)
                lru_page = min(memory, key=memory.get)
                del memory[lru_page]
            memory[page] = counter

        print(f"Page {page}: {'Fault' if page not in memory or memory.get(page)==counter else 'Hit'}")

    return page_faults

