#include <stdio.h>
#include <stdbool.h>

#define TLB_SIZE 4
#define PAGE_TABLE_SIZE 16

typedef struct {
    int virtual_page;
    int frame_number;
    bool valid;
} TLBEntry;

TLBEntry tlb[TLB_SIZE];
int tlb_index = 0;
int tlb_hits = 0;
int tlb_misses = 0;

// Initialize TLB
void init_tlb() {
    for (int i = 0; i < TLB_SIZE; i++) {
        tlb[i].valid = false;
    }
}

// TLB Lookup (simulated associative search)
int translate_tlb(int vpn) {
    for (int i = 0; i < TLB_SIZE; i++) {
        if (tlb[i].valid && tlb[i].virtual_page == vpn) {
            tlb_hits++;
            return tlb[i].frame_number;  // TLB Hit
        }
    }
    tlb_misses++;
    return -1;  // TLB Miss
}

// Add entry to TLB (FIFO replacement)
void add_tlb_entry(int vpn, int frame) {
    tlb[tlb_index].virtual_page = vpn;
    tlb[tlb_index].frame_number = frame;
    tlb[tlb_index].valid = true;
    tlb_index = (tlb_index + 1) % TLB_SIZE;
}

int main() {
    init_tlb();
    int virtual_addr = 0x1234;  // Example virtual address
    int page_size = 4096;

    int vpn = virtual_addr / page_size;
    int offset = virtual_addr % page_size;

    int frame = translate_tlb(vpn);
    if (frame == -1) {
        // Page table lookup would happen here
        frame = 5;  // Assume found in page table
        add_tlb_entry(vpn, frame);
    }

    int physical_addr = (frame * page_size) + offset;
    printf("TLB Hits: %d, Misses: %d\n", tlb_hits, tlb_misses);
    return 0;
}
